def crc32_1byte(data: bytearray, length: int, previous_crc32: int) -> int:
    crc = previous_crc32
    current_index = 0

    while length != 0:
        byte = data[current_index]
        table_index = ((crc >> 24) ^ byte) & 0xFF
        
        crc = ((crc << 8) & 0xFFFFFFFF) ^ Crc32Lookup[0][table_index]
        current_index += 1
        length -= 1
    return crc
